package pe.org.camaracomercioica.protestos.security; import lombok.RequiredArgsConstructor; import org.springframework.security.core.userdetails.*; import org.springframework.stereotype.Service; import pe.org.camaracomercioica.protestos.repository.UsuarioRepository; @Service @RequiredArgsConstructor public class DatabaseUserDetailsService implements UserDetailsService { private final UsuarioRepository repository; public UserDetails loadUserByUsername(String email){var u=repository.findByEmailIgnoreCase(email).orElseThrow(()->new UsernameNotFoundException("Credenciales inválidas"));return User.withUsername(u.getEmail()).password(u.getPasswordHash()).roles(u.getRol().getNombre()).disabled(!u.isActivo()).build();} }
